#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static void controller_set_filtering(controller_t *controller)
{
    controller->filter_on = true;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->clear_streak_count = 0;
}

static void controller_set_settling(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->settling_started_ms = controller->last_turbidity_ms;
}

static void controller_set_draining(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
    controller->clear_streak_count = 0;
}

static void controller_set_complete(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_COMPLETE;
}

static bool is_valid_input(const controller_input_t *input)
{
    return input != 0 && input->kind == CONTROLLER_INPUT_TURBIDITY ||
           input != 0 && input->kind == CONTROLLER_INPUT_LEVEL;
}

static void check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    bool needs_reset = false;

    if (controller->has_valid_turbidity && 
        controller->last_turbidity_ms != 0U &&
        (now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        needs_reset = true;
    }

    if (controller->has_valid_level &&
        controller->last_level_ms != 0U &&
        (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        needs_reset = true;
    }

    if (needs_reset) {
        controller_set_safe_idle(controller);
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    uint32_t now_ms = input.now_ms;

    /* Check for sensor timeout - forces safe idle if either sensor stale > 1000ms */
    check_sensor_timeout(controller, now_ms);

    /* Handle invalid/malformed inputs - go to safe idle */
    switch (input.kind) {
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit timeout signal - go to safe idle */
        controller_set_safe_idle(controller);
        break;

    case CONTROLLER_INPUT_NONE:
        /* No input - check if we should stay in current state or timeout */
        if (controller->has_valid_turbidity && controller->has_valid_level) {
            /* Both sensors valid, continue with current logic */
        } else if (controller->state == CONTROLLER_STATE_SAFE_IDLE ||
                   controller->state == CONTROLLER_STATE_COMPLETE) {
            /* Already in safe/complete state, no change needed */
        } else {
            /* In active state but no new input - check timeout condition */
            bool turb_stale = controller->has_valid_turbidity && 
                             (now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
            bool level_stale = controller->has_valid_level &&
                              (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;

            if (turb_stale || level_stale) {
                controller_set_safe_idle(controller);
            }
        }
        break;

    case CONTROLLER_INPUT_TURBIDITY:
    case CONTROLLER_INPUT_LEVEL:
        /* Process valid sensor input */
        break;
    }

    /* Now implement state machine logic based on current state and inputs */

    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        {
            /* Stay in SAFE_IDLE until both sensors are valid */
            if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
                controller->has_valid_turbidity = true;
                controller->last_turbidity_ntu = input.turbidity_ntu;
                controller->last_turbidity_ms = now_ms;
            } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
                controller->has_valid_level = true;
                controller->last_level = input.level;
                controller->last_level_ms = now_ms;
            }

            /* Check if both sensors are valid - can transition to FILTERING */
            if (controller->has_valid_turbidity && controller->has_valid_level) {
                /* Check LEVEL < 15 condition for COMPLETE state */
                if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                    controller_set_complete(controller);
                } else {
                    /* LEVEL >= 40 and both sensors valid - check for FILTERING */
                    if (input.kind == CONTROLLER_INPUT_TURBIDITY && 
                        controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                        controller_set_filtering(controller);
                    }
                }
            }
        }
        break;

    case CONTROLLER_STATE_FILTERING:
        {
            /* Update sensor values if received */
            if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
                controller->has_valid_turbidity = true;
                controller->last_turbidity_ntu = input.turbidity_ntu;
                controller->last_turbidity_ms = now_ms;

                /* Update clear streak based on turbidity */
                if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->clear_streak_count++;
                } else {
                    controller->clear_streak_count = 0;
                }
            } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
                controller->has_valid_level = true;
                controller->last_level = input.level;
                controller->last_level_ms = now_ms;

                /* Check LEVEL < 15 condition */
                if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                    controller_set_complete(controller);
                }
            }

            /* Check for transition to SETTLING: clear streak >= 3 and LEVEL >= 40 */
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                controller_set_settling(controller);
            }
        }
        break;

    case CONTROLLER_STATE_SETTLING:
        {
            /* Update sensor values if received */
            if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
                controller->has_valid_turbidity = true;
                controller->last_turbidity_ntu = input.turbidity_ntu;
                controller->last_turbidity_ms = now_ms;

                /* Update clear streak based on turbidity */
                if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller->clear_streak_count++;
                } else {
                    controller->clear_streak_count = 0;
                }
            } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
                controller->has_valid_level = true;
                controller->last_level = input.level;
                controller->last_level_ms = now_ms;

                /* Check LEVEL < 15 condition */
                if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                    controller_set_complete(controller);
                }
            }

            /* Check for disturbance: TURB > 40 resets streak and returns to FILTERING */
            if (input.kind == CONTROLLER_INPUT_TURBIDITY && 
                controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                controller_set_filtering(controller);
            }

            /* Check for transition to DRAINING: settle timer elapsed + clear sample + LEVEL >= 40 */
            if (controller->clear_streak_count == 1 && 
                controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Check if settle timer has elapsed (at least 400ms since settling started) */
                if (controller->last_turbidity_ms != 0U &&
                    (now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS) {
                    controller_set_draining(controller);
                }
            }
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        {
            /* Update sensor values if received */
            if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
                controller->has_valid_turbidity = true;
                controller->last_turbidity_ntu = input.turbidity_ntu;
                controller->last_turbidity_ms = now_ms;

                /* Check for disturbance: TURB > 50 and LEVEL >= 40 */
                if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                    controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Close drain, turn filter on, reset streak, return to FILTERING */
                    controller_set_filtering(controller);
                } else if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
                    /* Update clear streak even if no disturbance */
                    if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                        controller->clear_streak_count++;
                    } else {
                        controller->clear_streak_count = 0;
                    }
                }
            } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
                controller->has_valid_level = true;
                controller->last_level = input.level;
                controller->last_level_ms = now_ms;

                /* Check for disturbance: TURB > 50 and LEVEL >= 40 */
                if (controller->last_turbidity_ntu != 0 &&
                    controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                    controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Close drain, turn filter on, reset streak, return to FILTERING */
                    controller_set_filtering(controller);
                } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                    /* LEVEL < 15 - transition to COMPLETE */
                    controller_set_complete(controller);
                }
            }

            /* Check LEVEL < 15 condition */
            if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                controller_set_complete(controller);
            }
        }
        break;

    case CONTROLLER_STATE_COMPLETE:
        {
            /* Stay in COMPLETE, but check for timeout conditions */
            if (input.kind == CONTROLLER_INPUT_TURBIDITY || input.kind == CONTROLLER_INPUT_LEVEL) {
                /* Update sensor freshness */
                if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
                    controller->has_valid_turbidity = true;
                    controller->last_turbidity_ntu = input.turbidity_ntu;
                    controller->last_turbidity_ms = now_ms;
                } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
                    controller->has_valid_level = true;
                    controller->last_level = input.level;
                    controller->last_level_ms = now_ms;
                }

                /* Check timeout conditions */
                check_sensor_timeout(controller, now_ms);
            }
        }
        break;

    default:
        controller_set_safe_idle(controller);
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

